mapper.select:
SELECT
a.id id,
a.agent_id agentId,
a.agent_account agentAccount,
a.agent_name agentName,
a.order_no orderNo,
a.agent_status agentStatus,
a.commission_type commissionType,
a.apply_amount commissionAmount,
a.start_time startTime,
a.end_time endTime,
a.apply_time applyTime,
a.settle_time settleTime,
a.settle_status settleStatus,
a.order_status orderStatus,
a.currency currency,
a.settle_cycle settleCycle,
a.lock_status lockStatus,
IF(a.locker = #{adminName}, -1, 1) lockStatus1,
a.locker locker,
a.one_reviewer oneReviewer,
a.one_review_finish_time oneReviewFinishTime,
a.one_review_start_time oneReviewStartTime,
a.second_review_remark secondReviewRemark
FROM agent_commission_review_record a



        AND a.order_status in

            #{value}



        AND a.order_status  = #{vo.orderStatus}


        AND a.apply_time  >=  #{vo.applyStartTime}


        AND a.apply_time  <=  #{vo.applyEndTime}


        AND a.one_review_finish_time  >=  #{vo.auditStartTime}


        AND a.one_review_finish_time  <=  #{vo.auditEndTime}


        AND  a.agent_account =  #{vo.agentAccount}


        AND  a.site_code =  #{vo.siteCode}


        AND  a.commission_type =  #{vo.commissionType}


        AND a.order_no = #{vo.orderNo}


        AND a.settle_cycle = #{vo.settleCycle}


        AND a.lock_status = #{vo.lockStatus}


        AND a.locker = #{vo.locker}


        AND a.one_reviewer = #{vo.oneReviewer}



    ORDER BY  a.one_review_finish_time desc,a.id


    ORDER BY lockStatus1 ASC, a.lock_status ASC, a.apply_time desc

SELECT
a.id id,
a.agent_id agentId,
a.agent_account agentAccount,
a.agent_name agentName,
a.order_no orderNo,
a.agent_status agentStatus,
a.commission_type commissionType,
a.apply_amount commissionAmount,
a.start_time startTime,
a.end_time endTime,
a.apply_time applyTime,
a.settle_time settleTime,
a.settle_status settleStatus,
a.final_status orderStatus,
a.currency currency,
a.settle_cycle settleCycle,
a.one_reviewer oneReviewer,
a.one_review_finish_time oneReviewFinishTime,
a.one_review_start_time oneReviewStartTime,
a.one_review_remark oneReviewRemark,
a.second_review_remark secondReviewRemark,
a.second_review_start_time secondReviewStartTime,
a.second_review_finish_time secondReviewFinishTime,
a.second_reviewer secondReviewer,
a.adjust_commission_amount adjustCommissionAmount,
a.commission_amount ackCommissionAmount,
a.adjust_commission_remark adjustCommissionRemark
FROM agent_commission_review_record a



        AND a.final_status in

            #{value}



        AND a.final_status  = #{vo.orderStatus}


        AND a.apply_time  >=  #{vo.applyStartTime}


        AND a.apply_time  <=  #{vo.applyEndTime}


        AND a.one_review_finish_time  >=  #{vo.auditStartTime}


        AND a.one_review_finish_time  <=  #{vo.auditEndTime}


        AND  a.agent_account =  #{vo.agentAccount}


        AND  a.site_code =  #{vo.siteCode}


        AND  a.commission_type =  #{vo.commissionType}


        AND a.order_no = #{vo.orderNo}


        AND a.settle_cycle = #{vo.settleCycle}


        AND a.lock_status = #{vo.lockStatus}


        AND a.locker = #{vo.locker}


        AND a.one_reviewer = #{vo.oneReviewer}



    ORDER BY  a.one_review_finish_time desc,a.id


    ORDER BY lockStatus1 ASC, a.lock_status ASC, a.apply_time desc

SELECT count(1)
FROM agent_commission_review_record a



        AND a.order_status in

            #{value}



        AND a.apply_time  >=  #{vo.applyStartTime}


        AND a.apply_time  <=  #{vo.applyEndTime}


        AND  a.agent_account =  #{vo.agentAccount}


        AND  a.site_code =  #{vo.siteCode}


        AND  a.commission_type =  #{vo.commissionType}


        AND a.order_no = #{vo.orderNo}


        AND a.settle_cycle = #{vo.settleCycle}


        AND a.lock_status = #{vo.lockStatus}


        AND a.locker = #{vo.locker}

select sum(commission_amount) from agent_commission_review_record
where agent_id = #{agentId}
 and order_status = 3
